END_LINE=$(sed -n "$START_LINE,\$p" ./llvm/lib/Transforms/Utils/SCCPSolver.cpp | grep -n "^}" | head -1 | cut -d: -f1)
END_LINE=$((START_LINE + END_LINE - 1))

# Create clean function with minimal fix
cat <<'EOF' > /tmp/minimal_fix.cpp
void SCCPInstVisitor::visitCmpInst(CmpInst &I) {
  // Do not cache this lookup, getValueState calls later in the function might
  // invalidate the reference.
  if (ValueState[&I].isOverdefined())
    return (void)markOverdefined(&I);

  Value *Op1 = I.getOperand(0);
  Value *Op2 = I.getOperand(1);

  // For parameters, use ParamState which includes constant range info if
  // available.
  auto V1State = getValueState(Op1);
  auto V2State = getValueState(Op2);

  // Special handling: alloca vs non-null constant pointer comparisons
  // An alloca always returns a valid stack pointer, which can never equal
  // a compile-time constant pointer like inttoptr(i64 -1 to ptr).
  if (isa<AllocaInst>(Op1) && V2State.isConstant() && !V2State.getConstant()->isNullValue()) {
    if (I.isEquality()) {
      Constant *Result = (I.getPredicate() == ICmpInst::ICMP_EQ) 
                         ? ConstantInt::getFalse(I.getType())
                         : ConstantInt::getTrue(I.getType());
      return (void)markConstant(&I, Result);
    }
  }
