                         ? ConstantInt::getFalse(I.getType())
                         : ConstantInt::getTrue(I.getType());
      return (void)markConstant(&I, Result);
    }
  }

  Constant *C = V1State.getCompare(I.getPredicate(), I.getType(), V2State, DL);
  if (C) {
